(function() {
    var loaded = false;

    function loadDelayedScripts() {
        if (loaded) return;
        loaded = true;

        // Font Awesome — cargar primero (iconos visibles)
        var faScript = document.createElement('script');
        faScript.src = 'https://kit.fontawesome.com/79cd748ef8.js';
        faScript.async = true;
        document.body.appendChild(faScript);

        // Google Fonts — escalonado 100ms después para no competir con FA
        setTimeout(function() {
            var gfLink = document.createElement('link');
            gfLink.rel = 'stylesheet';
            gfLink.href = 'https://fonts.googleapis.com/css2?family=Merriweather:wght@300;400;700&family=Source+Sans+3:wght@300;400;500;600&display=swap';
            document.head.appendChild(gfLink);
        }, 100);

        // DebugBear RUM — escalonado 200ms después
        setTimeout(function() {
            (function(){
                var dbpr=100;
                if(Math.random()*100>100-dbpr) {
                    var d="dbbRum",w=window,o=document,a=addEventListener,scr=o.createElement("script");
                    scr.async=!0;
                    w[d]=w[d]||[];
                    w[d].push(["presampling",dbpr]);
                    ["error","unhandledrejection"].forEach(function(t){a(t,function(e){w[d].push([t,e])});});
                    scr.src="https://cdn.debugbear.com/UXhuUOpOTaBc.js";
                    o.body.appendChild(scr);
                }
            })();
        }, 200);
    }

    // Cargar en primera interacción del usuario
    var events = ['mousedown', 'keydown', 'touchstart', 'scroll'];
    events.forEach(function(event) {
        window.addEventListener(event, loadDelayedScripts, {once: true, passive: true});
    });

    // Fallback: requestIdleCallback cuando el browser esté idle, máximo 4s
    // Esto evita que todos los scripts terceros disparen exactamente al mismo tiempo (burst al segundo 3)
    if ('requestIdleCallback' in window) {
        requestIdleCallback(loadDelayedScripts, { timeout: 4000 });
    } else {
        setTimeout(loadDelayedScripts, 3000);
    }
})();

