			// Lazy-load Calendly iframe — only set src when the modal opens
		(function () {
			var utmKeys = ['utm_source', 'utm_medium', 'utm_campaign', 'utm_term', 'utm_content'];
			var urlParams = new URLSearchParams(window.location.search);

			function getCookie(name) {
				var match = document.cookie.match(new RegExp('(?:^|; )' + name.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '=([^;]*)'));
				return match ? decodeURIComponent(match[1]) : null;
			}

			function buildCalendlyUrl(baseSrc) {
				var utmPairs = [];
				utmKeys.forEach(function (key) {
					var val = urlParams.get(key) || getCookie('STYXKEY_' + key);
					if (val) utmPairs.push(encodeURIComponent(key) + '=' + encodeURIComponent(val));
				});
				return utmPairs.length ? baseSrc + '&' + utmPairs.join('&') : baseSrc;
			}

			var modal = document.getElementById('scheduleACall');
			if (modal) {
				modal.addEventListener('show.bs.modal', function () {
					var iframe = document.getElementById('calendly-iframe');
					if (iframe && !iframe.src) {
						iframe.src = buildCalendlyUrl(iframe.getAttribute('data-src'));
					}
				});
			}
		})();

		document.addEventListener("DOMContentLoaded", function () {
				const closeBtn = document.getElementById("close-btn");
				const searchBtn = document.getElementById("search-btn");
				const searchOverlay = document.getElementById("search-overlay");
				closeBtn.addEventListener("click", function () {
					searchOverlay.style.display = "none";
					searchBtn.style.display = "inline-block";
				});
				searchBtn.addEventListener("click", function () {
					this.style.display = "none";
					searchOverlay.style.display = "block";
				});
			});
